def _cadencia_mask_phone(phone):
    """Mascara o telefone: mantém só DDD e os 2 últimos dígitos."""
    digits = ''.join(ch for ch in str(phone or '') if ch.isdigit())
    if len(digits) < 4:
        return ''
    return digits[:2] + '•' * (len(digits) - 4) + digits[-2:]


